import 'package:flutter/material.dart';import '../core/config/api_config.dart';import '../core/config/content_url_resolver.dart';import '../core/network/dio_provider.dart';import '../core/storage/session_store.dart';import '../features/api_repository.dart';import '../features/models.dart';import 'theme.dart';import 'dart:io';import 'package:image_picker/image_picker.dart';import 'package:cached_network_image/cached_network_image.dart';
class MemeArenaApp extends StatefulWidget{const MemeArenaApp({super.key});@override State<MemeArenaApp> createState()=>_MemeArenaAppState();}
class _MemeArenaAppState extends State<MemeArenaApp>{late final store=SessionStore();late final config=ApiConfig();late final repo=ApiRepository(createDio(config),store.userId);String? userId;bool loading=true;@override void initState(){super.initState();store.userId().then((v)=>setState((){userId=v;loading=false;}));}void signedIn(String id)=>setState(()=>userId=id);Future<void> logout()async{await store.clear();setState(()=>userId=null);} @override Widget build(BuildContext context)=>MaterialApp(title:'Meme Arena',debugShowCheckedModeBanner:false,theme:darkTheme,home:loading?const Scaffold(body:Center(child:CircularProgressIndicator())):userId==null?Onboarding(repo:repo,store:store,onDone:signedIn):Home(repo:repo,store:store,config:config,onLogout:logout));}
class Onboarding extends StatefulWidget{const Onboarding({super.key,required this.repo,required this.store,required this.onDone});final ApiRepository repo;final SessionStore store;final ValueChanged<String> onDone;@override State<Onboarding> createState()=>_OnboardingState();}class _OnboardingState extends State<Onboarding>{final c=TextEditingController();String? err;bool busy=false;@override Widget build(BuildContext context)=>Scaffold(body:SafeArea(child:Center(child:SingleChildScrollView(padding:const EdgeInsets.all(24),child:Column(children:[Text('Meme Arena',style:Theme.of(context).textTheme.displaySmall),const SizedBox(height:24),TextField(controller:c,decoration:InputDecoration(labelText:'Nickname',errorText:err,border:const OutlineInputBorder())),const SizedBox(height:16),FilledButton(onPressed:busy?null:()async{final e=validateNickname(c.text);setState(()=>err=e);if(e!=null)return;setState(()=>busy=true);try{final u=await widget.repo.createGuest(c.text.trim());await widget.store.save(userId:u.id,nickname:u.nickname);widget.onDone(u.id);}catch(ex){setState(()=>err=ex.toString());}finally{if(mounted)setState(()=>busy=false);}},child:Text(busy?'Загрузка...':'Начать'))]))));}
class Home extends StatefulWidget{const Home({super.key,required this.repo,required this.store,required this.config,required this.onLogout});final ApiRepository repo;final SessionStore store;final ApiConfig config;final VoidCallback onLogout;@override State<Home> createState()=>_HomeState();}class _HomeState extends State<Home>{int i=0;@override Widget build(BuildContext c){final pages=[BattleScreen(repo:widget.repo,config:widget.config),TopScreen(repo:widget.repo,config:widget.config),UploadScreen(repo:widget.repo),ProfileScreen(repo:widget.repo,store:widget.store,onLogout:widget.onLogout)];return Scaffold(body:pages[i],bottomNavigationBar:NavigationBar(selectedIndex:i,onDestinationSelected:(v)=>setState(()=>i=v),destinations:const [NavigationDestination(icon:Icon(Icons.sports_mma),label:'Битва'),NavigationDestination(icon:Icon(Icons.leaderboard),label:'Топ'),NavigationDestination(icon:Icon(Icons.upload),label:'Загрузить'),NavigationDestination(icon:Icon(Icons.person),label:'Профиль')],));}}
class BattleScreen extends StatefulWidget{const BattleScreen({super.key,required this.repo,required this.config});final ApiRepository repo;final ApiConfig config;@override State<BattleScreen> createState()=>_BattleScreenState();}class _BattleScreenState extends State<BattleScreen>{Battle? b;String? error;bool loading=true;@override void initState(){super.initState();load();}Future<void> load()async{setState((){loading=true;error=null;});try{b=await widget.repo.getNextBattle();}catch(e){error=e.toString();}setState(()=>loading=false);}Future<void> vote(String id)async{final r=await widget.repo.submitVote(b!,id);if(mounted)ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(r.prediction.created?'Прогноз сохранён — Если мем станет хитом, ты получишь очки скаута':'Голос учтён')));load();}@override Widget build(c)=>SafeArea(child:loading?const Center(child:CircularProgressIndicator()):error!=null?Center(child:Text('Ошибка: $error')):b==null?const Center(child:Text('Пока нет доступных пар')):ListView(padding:const EdgeInsets.all(16),children:[Text('Какой мем смешнее?',style:Theme.of(c).textTheme.headlineMedium,textAlign:TextAlign.center),MemeCard(m:b!.left,config:widget.config,onTap:()=>vote(b!.left.id)),const Center(child:Text('VS')),MemeCard(m:b!.right,config:widget.config,onTap:()=>vote(b!.right.id))]));}
class MemeCard extends StatelessWidget{const MemeCard({super.key,required this.m,required this.config,this.onTap});final MemeItem m;final ApiConfig config;final VoidCallback? onTap;@override Widget build(c){final url=ContentUrlResolver(config).resolve(m.imageUrl);return Card(clipBehavior:Clip.antiAlias,child:InkWell(onTap:onTap,child:Column(children:[AspectRatio(aspectRatio:4/3,child:CachedNetworkImage(imageUrl:url,fit:BoxFit.cover,errorWidget:(_,__,___)=>const Icon(Icons.broken_image,size:48))),ListTile(title:Text(m.title),subtitle:Text('Рейтинг ${m.rating}'))])));}}
class TopScreen extends StatefulWidget{const TopScreen({super.key,required this.repo,required this.config});final ApiRepository repo;final ApiConfig config;@override State<TopScreen> createState()=>_TopScreenState();}class _TopScreenState extends State<TopScreen>{int tab=0;String scoutPeriod='WEEK';@override Widget build(c)=>SafeArea(child:Column(children:[SegmentedButton<int>(segments:const [ButtonSegment(value:0,label:Text('Мемы')),ButtonSegment(value:1,label:Text('Скауты'))],selected:{tab},onSelectionChanged:(v)=>setState(()=>tab=v.first)),if(tab==1)SegmentedButton<String>(segments:const [ButtonSegment(value:'WEEK',label:Text('Неделя')),ButtonSegment(value:'ALL_TIME',label:Text('Всё время'))],selected:{scoutPeriod},onSelectionChanged:(v)=>setState(()=>scoutPeriod=v.first)),Expanded(child:tab==0?_MemesTop(repo:widget.repo):_ScoutsTop(repo:widget.repo,period:scoutPeriod))]));}
class _MemesTop extends StatelessWidget{const _MemesTop({required this.repo});final ApiRepository repo;@override Widget build(c)=>FutureBuilder<List<MemeItem>>(future:repo.getTop(),builder:(c,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());if(s.hasError)return Center(child:Text('Ошибка: ${s.error}'));final items=s.data??[];if(items.isEmpty)return const Center(child:Text('Топ пока пуст'));return ListView.builder(itemCount:items.length,itemBuilder:(c,i){final m=items[i];return ListTile(leading:Text('${m.position??i+1}'),title:Text(m.title),subtitle:Text('Рейтинг ${m.rating} · ${m.wins}/${m.losses}/${m.battlesCount}'));});});}
class _ScoutsTop extends StatelessWidget{const _ScoutsTop({required this.repo,required this.period});final ApiRepository repo;final String period;@override Widget build(c)=>FutureBuilder<List<ScoutLeaderboardItem>>(future:repo.getScoutLeaderboard(period:period),builder:(c,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());if(s.hasError)return Center(child:Text('Ошибка: ${s.error}'));final items=s.data??[];if(items.isEmpty)return const Center(child:Text('Скаутов пока нет'));return ListView.builder(itemCount:items.length,itemBuilder:(c,i){final x=items[i];final acc=x.accuracy==null?'—':'${(x.accuracy!*100).toStringAsFixed(0)}%';return ListTile(leading:Text('${x.position}'),title:Text(x.nickname),subtitle:Text('${rankTitle(x.rank)} · ${x.scoutPoints} очков · точность $acc'));});});}
class UploadScreen extends StatefulWidget{const UploadScreen({super.key,required this.repo});final ApiRepository repo;@override State<UploadScreen> createState()=>_UploadScreenState();}class _UploadScreenState extends State<UploadScreen>{final title=TextEditingController(),src=TextEditingController(),imageUrl=TextEditingController();String? path,msg;bool busy=false;@override Widget build(c)=>SafeArea(child:ListView(padding:const EdgeInsets.all(16),children:[Text('Загрузить мем',style:Theme.of(c).textTheme.headlineMedium),OutlinedButton(onPressed:()async{final x=await ImagePicker().pickImage(source:ImageSource.gallery);if(x!=null)setState(()=>path=x.path);},child:Text(path==null?'Выбрать изображение':'Изображение выбрано')),if(path!=null)Image.file(File(path!),height:180),TextField(controller:title,decoration:const InputDecoration(labelText:'Title')),TextField(controller:src,decoration:const InputDecoration(labelText:'Source URL (optional)')),TextField(controller:imageUrl,decoration:const InputDecoration(labelText:'Image URL fallback')),FilledButton(onPressed:busy?null:()async{if(title.text.trim().isEmpty||(path==null&&imageUrl.text.trim().isEmpty)){setState(()=>msg='Заполните title и выберите изображение или укажите imageUrl');return;}setState(()=>busy=true);try{String? mediaId;if(path!=null){try{mediaId=(await widget.repo.uploadImage(File(path!))).id;}catch(_){mediaId=null;}}await widget.repo.createMeme(title:title.text.trim(),mediaAssetId:mediaId,imageUrl:mediaId==null?imageUrl.text.trim():null,sourceUrl:src.text.trim());setState((){msg='Мем отправлен на модерацию';path=null;title.clear();src.clear();imageUrl.clear();});}catch(e){setState(()=>msg=e.toString());}finally{setState(()=>busy=false);}},child:const Text('Отправить')),if(msg!=null)Text(msg!)]));}
