class ProfileScreen extends StatefulWidget{const ProfileScreen({super.key,required this.repo,required this.store,required this.onLogout});final ApiRepository repo;final SessionStore store;final VoidCallback onLogout;@override State<ProfileScreen> createState()=>_ProfileScreenState();}class _ProfileScreenState extends State<ProfileScreen>{late Future<UserProfile> f;@override void initState(){super.initState();f=widget.store.userId().then((id)=>widget.repo.getProfile(id!));}@override Widget build(c)=>SafeArea(child:FutureBuilder<UserProfile>(future:f,builder:(c,s){if(!s.hasData)return const Center(child:CircularProgressIndicator());final u=s.data!;final acc=u.accuracy==null?'—':'${(u.accuracy!*100).toStringAsFixed(0)}%';return ListView(padding:const EdgeInsets.all(16),children:[Text(u.nickname,style:Theme.of(c).textTheme.headlineMedium),Text('Ранг: ${rankTitle(u.rank)}'),Text('Очки скаута: ${u.scoutPoints}'),Text('Точность: $acc'),Text('Прогнозов: ${u.predictionsCount}'),Text('Успешных: ${u.successfulPredictions}'),Text('Серия: ${u.currentSuccessStreak}'),Text('Лучшая серия: ${u.bestSuccessStreak}'),Text('Голосов: ${u.votesCount}'),Text('Мемов: ${u.submittedMemesCount}'),OutlinedButton(onPressed:()=>Navigator.of(c).push(MaterialPageRoute(builder:(_)=>PredictionsScreen(repo:widget.repo))),child:const Text('Мои прогнозы')),if(u.achievements.isNotEmpty)Text('Достижения',style:Theme.of(c).textTheme.titleLarge),...u.achievements.map((a)=>ListTile(title:Text(a.title),subtitle:Text(a.description))),OutlinedButton(onPressed:widget.onLogout,child:const Text('Сменить пользователя'))]);}));}
